import{_ as e,o as t,c as a,R as s}from"./chunks/framework.g9eZ-ZSs.js";const f=JSON.parse('{"title":"Generated C# DTOs","description":"","frontmatter":{},"headers":[],"relativePath":"stacks/agnostic/dtos.md","filePath":"stacks/agnostic/dtos.md"}'),o={name:"stacks/agnostic/dtos.md"},r=s('<h1 id="generated-c-dtos" tabindex="-1">Generated C# DTOs <a class="header-anchor" href="#generated-c-dtos" aria-label="Permalink to &quot;Generated C# DTOs&quot;">​</a></h1><p>Data Transfer Objects, or DTOs, allow for transformations of data from the data store into a format more suited for transfer and use on the client side. This often means trimming properties and flattening structures to provide a leaner over-the-wire experience. Coalesce aims to support this as seamlessly as possible.</p><p>Coalesce supports two types of DTOs:</p><ul><li>DTOs that are automatically generated for each POCO database object. These are controlled via <a href="/Coalesce/modeling/model-components/attributes.html">Attributes</a> on the POCO. These are outlined below.</li><li>DTOs that you create with IClassDto. These are outlined at <a href="/Coalesce/modeling/model-types/dtos.html">Custom DTOs</a>.</li></ul><h2 id="automatically-generated-dtos" tabindex="-1">Automatically Generated DTOs <a class="header-anchor" href="#automatically-generated-dtos" aria-label="Permalink to &quot;Automatically Generated DTOs&quot;">​</a></h2><p>Every class that is exposed through Coalesce&#39;s generated API will have a corresponding DTO generated for it. These DTOs are used to shuttle data back and forth to the client. They are generated classes that have nullable versions of all the properties on the POCO class.</p><p><a href="/Coalesce/modeling/model-components/attributes/dto-includes-excludes.html">[DtoIncludes] &amp; [DtoExcludes]</a> and the <a href="/Coalesce/concepts/includes.html">Includes String</a> infrastructure can be used to indicate which properties should be transferred to the client in which cases, and <a href="/Coalesce/concepts/include-tree.html">Include Tree</a> is used to dictate how these DTOs are constructed from POCOs retrieved from the database.</p><p>The <a href="/Coalesce/modeling/model-components/attributes/security-attribute.html">[Read] and [Edit] attributes</a> can be used to apply property-level security, which manifests as conditional logic in the mapping methods on the generated DTOs.</p><p>See the <a href="/Coalesce/topics/security.html#property-column-security">Security</a> page to read more about property-level security, as well as all other security mechanisms in Coalesce.</p>',9),l=[r];function n(i,c,d,h,u,p){return t(),a("div",null,l)}const T=e(o,[["render",n]]);export{f as __pageData,T as default};
